@rendermode InteractiveServer
@using sv_4eb675130e3c425da93c37e04d52e372.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel">
        @if (_activeChannel is not null)
        {
            <MessageArea Channel="_activeChannel"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         IsLoadingMore="_isLoadingMore"
                         HasMoreMessages="_hasMoreMessages"
                         OnLoadMore="LoadMoreMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="thread-panel-wrapper">
            <ThreadPanel RootMessage="_threadRootMessage"
                         ThreadMessages="_threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    private bool _threadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;
        ComputeThreadReplyCounts();
        CloseThread();

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (_activeChannelId is null || _isLoadingMore) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            ComputeThreadReplyCounts();
        }
        _hasMoreMessages = older.Count >= PageSize;
        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        var allThreadMessages = await ChatService.GetThreadAsync(rootMessageId);
        _threadMessages = allThreadMessages.Where(m => m.Id != rootMessageId).ToList();
        _threadOpen = true;

        // Update the reply count for this thread
        _threadReplyCounts[rootMessageId] = _threadMessages.Count;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_activeChannelId is null || _threadRootId is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootId);
        _threadMessages.Add(reply);
        _threadReplyCounts[_threadRootId.Value] = _threadMessages.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
            ComputeThreadReplyCounts();
        }
    }

    private void ComputeThreadReplyCounts()
    {
        _threadReplyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

