{"path": "/tmp/sv-4eb675130e3c425da93c37e04d52e372/Components/Pages/Chat/MessageArea.razor", "file_text": "@using sv_4eb675130e3c425da93c37e04d52e372.Services

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel?.Name</h2>
        <p>@Channel?.Description</p>
    </div>

    <div class="message-list">
        @if (HasMoreMessages)
        {
            <div class="load-more-container">
                <button class="load-more-btn" @onclick="OnLoadMore" disabled="@IsLoadingMore">
                    @(IsLoadingMore ? "Loading…" : "Load older messages")
                </button>
            </div>
        }

        @foreach (var msg in TopLevelMessages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="OnReact" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-textarea"
                  @bind="newMessage"
                  @bind:event="oninput"
                  placeholder="Message #@Channel?.Name"
                  rows="2"></textarea>
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(newMessage)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private string newMessage = "";

    private IEnumerable<Message> TopLevelMessages =>
        Messages.Where(m => m.ReplyToId == null);

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(newMessage)) return;
        var content = newMessage.Trim();
        newMessage = "";
        await OnSendMessage.InvokeAsync(content);
    }
}
"}

