toolArgs.file_text:
@using sv_4eb675130e3c425da93c37e04d52e372.Services

<div class="message-bubble" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    <span>@reaction.Emoji</span>
                    <span class="reaction-count">@reaction.Users.Count</span>
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀 React</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff switch
        {
            { TotalMinutes: < 1 } => "just now",
            { TotalMinutes: < 60 } => $"{(int)diff.TotalMinutes} min ago",
            { TotalHours: < 24 } => $"{(int)diff.TotalHours}h ago",
            { TotalDays: < 7 } => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

