.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #36393f;
    color: #dcddde;
}

.message-area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #2c2f33;
    flex-shrink: 0;
}

.message-area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
    font-weight: 700;
}

.message-area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.load-more-container {
    text-align: center;
    padding: 8px;
}

.load-more-btn {
    background: none;
    border: 1px solid #4f545c;
    color: #00aff4;
    padding: 6px 16px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.85rem;
    transition: background-color 0.15s;
}

.load-more-btn:hover:not(:disabled) {
    background-color: #2f3136;
}

.load-more-btn:disabled {
    color: #72767d;
    cursor: not-allowed;
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #2c2f33;
    flex-shrink: 0;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    background-color: #40444b;
    border: none;
    border-radius: 8px;
    color: #dcddde;
    padding: 10px 14px;
    font-size: 0.95rem;
    font-family: inherit;
    resize: none;
    outline: none;
}

.message-textarea::placeholder {
    color: #72767d;
}

.message-textarea:focus {
    box-shadow: 0 0 0 1px #5865f2;
}

.send-btn {
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 20px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-btn:disabled {
    background-color: #4f545c;
    cursor: not-allowed;
}

