toolArgs.file_text:
@using sv_4eb675130e3c425da93c37e04d52e372.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-header">
                <span class="author">@RootMessage.Author</span>
                <span class="timestamp">@FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>
    }

    <div class="thread-messages">
        @foreach (var msg in ThreadMessages)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="author">@msg.Author</span>
                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                </div>
                <div class="reply-content">@msg.Content</div>
            </div>
        }
    </div>

    <div class="thread-input-area">
        <textarea class="thread-textarea"
                  @bind="replyText"
                  @bind:event="oninput"
                  placeholder="Reply…"
                  rows="2"></textarea>
        <button class="reply-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(replyText)">
            Reply
        </button>
    </div>
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string replyText = "";

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(replyText)) return;
        var content = replyText.Trim();
        replyText = "";
        await OnSendReply.InvokeAsync(content);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff switch
        {
            { TotalMinutes: < 1 } => "just now",
            { TotalMinutes: < 60 } => $"{(int)diff.TotalMinutes} min ago",
            { TotalHours: < 24 } => $"{(int)diff.TotalHours}h ago",
            { TotalDays: < 7 } => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #36393f;
    border-left: 1px solid #2c2f33;
